import Slardar from '@slardar/base'
import { sanitizeErrorMessage, shouldFilterError } from './blacklist'
import { electronFetchTransport } from './transports/electronFetch'
import { getFallbackDid } from '../fallbackDid'

Slardar.init({
  bid: 'luna_pc',
  transport: electronFetchTransport,
  pid: 'background',
  deviceId: getFallbackDid(),
  userId: getFallbackDid(),
  release: APP_VERSION,
  env: IS_DEV ? 'development' : 'production',
})

Slardar.start()

const originalConsoleError = console.error.bind(console)

process.on('uncaughtException', (error) => {
  originalConsoleError(error)
  collectError(error)
})

process.on('unhandledRejection', (error) => {
  originalConsoleError(error)
  collectError(error)
})

console.error = (...args: any[]) => {
  originalConsoleError(...args)
  for (const arg of args) {
    if (arg instanceof Error) {
      collectError(arg)
    }
  }
}

export function collectError(error: unknown) {
  // 检查黑名单，如果命中则不上报
  if (shouldFilterError(error)) {
    return
  }

  if (error instanceof Error) {
    Slardar.report({
      ev_type: 'js_error',
      payload: {
        error: {
          name: error.name,
          message: sanitizeErrorMessage(error.message),
          stack: error.stack ? sanitizeErrorMessage(error.stack) : undefined,
        },
        breadcrumbs: [],
      },
    })
  } else {
    Slardar.report({
      ev_type: 'js_error',
      payload: {
        error: {
          name: 'Unknown Error',
          message: sanitizeErrorMessage(String(error)),
        },
        breadcrumbs: [],
      },
    })
  }
}
