import './utils/slardar/background'
import Slardar from '@slardar/base'
import path from 'node:path'
import fs from 'node:fs'
import { app, dialog, shell } from 'electron'
import semver from 'semver'

globalThis.shellVersion = APP_VERSION
globalThis.isSmallPackage = false

try {
  if (process.mas) {
    throw new Error('MAS 环境禁用小包更新')
  }

  let packagesDir: string
  if (process.platform === 'win32') {
    const multiVersionDir = path.dirname(path.dirname(app.getPath('exe')))
    const multiVersionDirFiles = fs.readdirSync(multiVersionDir)
    if (multiVersionDirFiles.includes('Packages')) {
      packagesDir = path.resolve(multiVersionDir, 'Packages')
    } else {
      packagesDir = path.resolve(app.getPath('userData'), 'Packages')
    }
  } else {
    packagesDir = path.resolve(app.getPath('userData'), 'Packages')
  }

  const configPath = path.resolve(packagesDir, 'config.json')

  const configFile = fs.readFileSync(configPath, 'utf-8')
  const configJson = JSON.parse(configFile)

  const targetPackagePath = path.resolve(packagesDir, configJson.latestVersion)
  const manifestPath = path.resolve(targetPackagePath, 'manifest.json')
  const manifestFile = fs.readFileSync(manifestPath, 'utf-8')
  const manifest = JSON.parse(manifestFile)

  if (manifest.version !== configJson.latestVersion) {
    throw new Error('版本异常不匹配')
  }

  if (!semver.gte(APP_VERSION, manifest.shellMinVersion)) {
    throw new Error('不满足最低 Shell 要求')
  }

  if (semver.gte(APP_VERSION, manifest.version)) {
    // 相同主要为了在小包更新出现问题的时候，用户能够从官网下载最新包去解决
    throw new Error('Shell 版本比 Package 版本相同或更高')
  }

  const targetEntry = path.resolve(targetPackagePath, 'app.asar/main.js')
  globalThis.isSmallPackage = true

  Slardar.config({ release: manifest.version })
  require(targetEntry)
} catch (e) {
  try {
    console.error(e)
    require(path.resolve(__dirname, 'main.js'))
  } catch (e) {
    console.error(e)
    app.whenReady().then(() => {
      const result = dialog.showMessageBoxSync(null as never, {
        title: '启动失败',
        message: '汽水音乐启动失败，可能是由于程序文件发生了损坏。请您访问官网手动下载安装。',
        defaultId: 0,
        buttons: [
          '官网下载',
          '退出',
        ],
      })
      if (result === 0) {
        shell.openExternal('https://www.qishui.com/')
      } else {
        app.exit()
      }
    })
  }
}
