const native = require('bindings')('ttnet')
const { Readable } = require('stream')
const { Buffer } = require('buffer')

let isShuttingDown = false

/**
 * Make an HTTP request
 * @param {import('./index').RequestOptions} options - Request options
 * @returns {Promise<import('./index').Response>}
 */
async function request(options) {
  if (isShuttingDown) {
    return new Promise(() => {})
  }

  return new Promise((resolve, reject) => {
    let requestHandle = null
    let abortHandler = null
    let responseInfo = null
    let responseResolved = false

    // Setup AbortSignal handler
    if (options.signal) {
      if (options.signal.aborted) {
        reject(new Error('Request was aborted'))
        return
      }

      abortHandler = () => {
        if (requestHandle) {
          native.cancel(requestHandle)
        }
      }
      options.signal.addEventListener('abort', abortHandler)
    }

    // Create a readable stream for response body
    const bodyStream = new Readable({
      read() {
        // No-op, data is pushed from callbacks
      },
    })

    // Normalize options - convert headers to multi-value format
    const normalizedHeaders = {}
    if (options.headers) {
      for (const [key, value] of Object.entries(options.headers)) {
        if (Array.isArray(value)) {
          normalizedHeaders[key] = value
        } else {
          normalizedHeaders[key] = [value]
        }
      }
    }

    const normalizedOptions = {
      url: options.url,
      method: options.method || 'GET',
      headers: normalizedHeaders,
      followRedirects: options.followRedirects !== undefined ? options.followRedirects : true,
    }

    // Add timeout options if provided
    if (options.connectTimeout !== undefined) {
      normalizedOptions.connectTimeout = options.connectTimeout
    }
    if (options.readTimeout !== undefined) {
      normalizedOptions.readTimeout = options.readTimeout
    }
    if (options.writeTimeout !== undefined) {
      normalizedOptions.writeTimeout = options.writeTimeout
    }
    if (options.requestTimeout !== undefined) {
      normalizedOptions.requestTimeout = options.requestTimeout
    }

    // Setup unified event callback
    const callbacks = {
      onEvent: (event) => {
        switch (event.type) {
          case 'response':
            responseInfo = event
            responseResolved = true
            // Convert headers to multi-value format
            const multiValueHeaders = {}
            for (const [key, value] of Object.entries(event.headers)) {
              if (Array.isArray(value)) {
                multiValueHeaders[key] = value
              } else {
                multiValueHeaders[key] = [value]
              }
            }

            // Resolve immediately when response headers are received (streaming starts)
            resolve({
              statusCode: event.statusCode,
              statusText: event.statusText,
              headers: multiValueHeaders,
              protocol: event.protocol,
              negotiatedProtocol: event.negotiatedProtocol,
              url: event.url,
              proxyServer: event.proxyServer,
              receivedByteCount: event.receivedByteCount,
              wasCached: event.wasCached,
              body: bodyStream,
            })
            break

          case 'data':
            bodyStream.push(event.data)
            break

          case 'end':
            bodyStream.push(null)
            if (abortHandler && options.signal) {
              options.signal.removeEventListener('abort', abortHandler)
            }
            break

          case 'error':
            if (abortHandler && options.signal) {
              options.signal.removeEventListener('abort', abortHandler)
            }
            if (responseResolved) {
              // Response already resolved, emit error through stream
              bodyStream.destroy(event.error)
            } else {
              // Response not yet resolved, reject promise
              bodyStream.destroy()
              reject(event.error)
            }
            break
        }
      },
    }

    // Handle request body - must be a Buffer (complete data in memory)
    if (options.body) {
      if (Buffer.isBuffer(options.body)) {
        normalizedOptions.body = options.body
      } else {
        reject(new Error('Request body must be a Buffer'))
        return
      }
    }

    requestHandle = native.request(normalizedOptions, callbacks)
  })
}

/**
 * Initialize TTNet engine with configuration
 * @param {import('./index').TTNetInitOptions} options - Initialization options
 */
function initTTNet(options) {
  native.initTTNet(options)
}

function shutdownTTNet(options) {
  isShuttingDown = true
  native.shutdownTTNet(options)
}

module.exports = {
  initTTNet,
  shutdownTTNet,
  request,
  hello: () => native.hello(),
}
