import type { CookiesSetDetails } from 'electron'
import { createHash } from 'node:crypto'
import { app, session } from 'electron'
import { request as ttnetRequest, type RequestOptions as TTNetRequestOptions, type Response as TTNetResponse } from '@luna/ttnet'
import * as setCookieParser from 'set-cookie-parser'
import { Readable } from 'stream'

/**
 * 请求拦截器参数类型定义
 */
export interface RequestInfo {
  id: number
  url: string
  method: string
  timestamp: number
  referrer?: string
  resourceType?: string
}

export interface BeforeSendHeadersParams extends RequestInfo {
  requestHeaders: Record<string, string[]>
}

export interface HeadersReceivedParams extends RequestInfo {
  statusCode: number
  statusLine: string
  responseHeaders: Record<string, string[]>
}

export interface CompletedParams extends RequestInfo {
  statusCode?: number
  statusLine?: string
  fromCache: boolean
  error?: string
  responseHeaders?: Record<string, string[]>
}

type BeforeSendHeadersInterceptor = (params: BeforeSendHeadersParams) => Promise<Record<string, string[]>> | Record<string, string[]>
type HeadersReceivedInterceptor = (params: HeadersReceivedParams) => void
type CompletedInterceptor = (params: CompletedParams) => void
type BeforeRequestInterceptor = (params: RequestInfo) => void

const beforeSendHeadersInterceptors: BeforeSendHeadersInterceptor[] = []
const headersReceivedInterceptors: HeadersReceivedInterceptor[] = []
const completedInterceptors: CompletedInterceptor[] = []
const beforeRequestInterceptors: BeforeRequestInterceptor[] = []

/**
 * 拦截请求发送前的 headers
 * @param interceptor 拦截器函数，接收请求信息和 headers，返回修改后的 headers
 */
export function interceptBeforeSendHeaders(interceptor: BeforeSendHeadersInterceptor) {
  beforeSendHeadersInterceptors.push(interceptor)
}

/**
 * 拦截响应头接收
 * @param interceptor 拦截器函数，接收请求信息和响应头
 */
export function interceptHeadersReceived(interceptor: HeadersReceivedInterceptor) {
  headersReceivedInterceptors.push(interceptor)
}

/**
 * 拦截请求完成（包括成功和失败）
 * @param interceptor 拦截器函数，接收请求信息、状态码和可选的错误信息
 */
export function interceptCompleted(interceptor: CompletedInterceptor) {
  completedInterceptors.push(interceptor)
}

/**
 * 拦截请求发送前
 * @param interceptor 拦截器函数，接收请求信息
 */
export function interceptBeforeRequest(interceptor: BeforeRequestInterceptor) {
  beforeRequestInterceptors.push(interceptor)
}

/**
 * 转换 SameSite 值为 Electron 期望的格式
 */
function convertSameSiteValue(sameSite: string): CookiesSetDetails['sameSite'] {
  const normalizedValue = sameSite.toLowerCase()
  switch (normalizedValue) {
    case 'none':
      return 'no_restriction'
    case 'lax':
      return 'lax'
    case 'strict':
      return 'strict'
    default:
      return 'unspecified'
  }
}

let requestIdCounter = 0

/**
 * 合并两个 cookie 头字符串，相同名称的 cookie 优先使用第一个参数的
 * @param requestCookie 请求头中的 cookie
 * @param sessionCookie session 中的 cookie
 * @returns 合并后的 cookie 字符串
 */
function mergeCookieHeaders(requestCookie?: string, sessionCookie?: string): string | undefined {
  const parseCookies = (cookieStr?: string): Record<string, string> => {
    if (!cookieStr) return {}
    const cookies: Record<string, string> = {}
    cookieStr.split(';').forEach((part) => {
      const [name, value] = part.trim().split('=')
      if (name && value) {
        cookies[name.trim()] = value.trim()
      }
    })
    return cookies
  }

  const sessionCookies = parseCookies(sessionCookie)
  const requestCookies = parseCookies(requestCookie)

  // 合并 cookies，requestCookies 优先级更高
  const mergedCookies = { ...sessionCookies, ...requestCookies }

  // 转换为字符串
  const cookieParts = Object.entries(mergedCookies).map(([name, value]) => `${name}=${value}`)
  return cookieParts.length > 0 ? cookieParts.join('; ') : undefined
}

function hasHeader(headers: Record<string, string[]>, name: string): boolean {
  const normalizedName = name.toLowerCase()
  return Object.keys(headers).some(key => key.toLowerCase() === normalizedName)
}

function setBodyMd5Header(headers: Record<string, string[]>, bodyMd5: string | null) {
  if (!bodyMd5 || hasHeader(headers, 'x-ss-stub')) return
  headers['X-SS-STUB'] = [bodyMd5]
}

function toBufferView(chunk: Uint8Array): Buffer {
  return Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk.buffer, chunk.byteOffset, chunk.byteLength)
}

/**
 * 使用 TTNet 库发送 HTTP 请求，支持 HTTP/2 和流式处理
 * @param req 原始 Request 对象
 * @returns Promise<Response>
 */
export async function sendHttpRequest(req: Request): Promise<Response> {
  const requestId = ++requestIdCounter
  const startTimestamp = Date.now()

  try {
    // 触发 beforeRequest 拦截器
    for (const interceptor of beforeRequestInterceptors) {
      interceptor({
        id: requestId,
        url: req.url,
        method: req.method,
        timestamp: startTimestamp,
        referrer: req.referrer,
      })
    }

    // 获取 session cookies（仅在 app 准备就绪时）
    let requestHeaders: Record<string, string[]> = {}
    // 将 Headers 对象转换为多值格式
    for (const [key, value] of req.headers.entries()) {
      if (!requestHeaders[key]) {
        requestHeaders[key] = []
      }
      requestHeaders[key].push(value)
    }
    // 合并 session cookies 和请求头 cookies
    const sessionCookieHeader = await getCookiesHeader(req.url)
    const mergedCookie = mergeCookieHeaders(requestHeaders.cookie?.[0], sessionCookieHeader ?? undefined)
    if (mergedCookie) {
      requestHeaders.cookie = [mergedCookie]
    }

    // 将请求体完整读取到 Buffer 中（支持 rewind），并在签名前补齐 TTNet rs.29 需要的 body 摘要头
    let bodyBuffer: Buffer | null = null
    let bodyMd5: string | null = null
    if (req.body) {
      const chunks: Uint8Array[] = []
      const shouldComputeBodyMd5 = !hasHeader(requestHeaders, 'x-ss-stub')
      const bodyHash = shouldComputeBodyMd5 ? createHash('md5') : null
      let totalLength = 0
      const reader = req.body.getReader()
      while (true) {
        const { done, value } = await reader.read()
        if (done) break
        if (value) {
          chunks.push(value)
          totalLength += value.byteLength
          bodyHash?.update(value)
        }
      }
      bodyBuffer = chunks.length === 1 ? toBufferView(chunks[0]) : Buffer.concat(chunks, totalLength)
      bodyMd5 = bodyHash?.digest('hex').toUpperCase() ?? null
    }
    setBodyMd5Header(requestHeaders, bodyMd5)

    // 触发 beforeSendHeaders 拦截器
    for (const interceptor of beforeSendHeadersInterceptors) {
      const modifiedHeaders = await interceptor({
        id: requestId,
        url: req.url,
        method: req.method,
        timestamp: startTimestamp,
        referrer: req.referrer,
        requestHeaders: requestHeaders,
      })
      requestHeaders = modifiedHeaders
    }

    const response = await ttnetRequest({
      url: req.url,
      method: req.method,
      headers: requestHeaders,
      body: bodyBuffer,
      followRedirects: req.redirect !== 'manual' && req.redirect !== 'error',
      signal: req.signal,
      requestTimeout: 30000, // 30秒超时
    })

    // 直接修改 response.headers：过滤 HTTP/2 伪头部并转为小写
    const filteredHeaders: Record<string, string[]> = {}
    for (const [key, value] of Object.entries(response.headers)) {
      if (!key.startsWith(':')) {
        filteredHeaders[key.toLowerCase()] = value
      }
    }
    response.headers = filteredHeaders

    // 触发 headersReceived 拦截器
    for (const interceptor of headersReceivedInterceptors) {
      interceptor({
        id: requestId,
        url: req.url,
        method: req.method,
        timestamp: startTimestamp,
        referrer: req.referrer,
        statusCode: response.statusCode,
        statusLine: '',
        responseHeaders: response.headers,
      })
    }

    // 处理 Set-Cookie 头
    if (response.headers['set-cookie']) {
      await saveCookiesWithHeader(req.url, response.headers['set-cookie'])
    }

    // 触发 completed 拦截器
    for (const interceptor of completedInterceptors) {
      interceptor({
        id: requestId,
        url: req.url,
        method: req.method,
        timestamp: startTimestamp,
        referrer: req.referrer,
        statusCode: response.statusCode,
        statusLine: '',
        fromCache: response.wasCached || false,
      })
    }

    // 某些状态码不允许有 body (204, 304等)
    const shouldHaveBody = response.statusCode !== 204 && response.statusCode !== 304 && response.statusCode !== 1223

    // 将 Node.js Readable 转换为 Web ReadableStream
    const responseBody = shouldHaveBody ? Readable.toWeb(response.body) as unknown as ReadableStream<Uint8Array> : null

    // 将多值 headers 转换为 Web Headers 对象
    const responseHeadersObj = new Headers()
    for (const [key, values] of Object.entries(response.headers)) {
      for (const value of values) {
        responseHeadersObj.append(key, value)
      }
    }

    return new Response(responseBody, {
      status: response.statusCode,
      statusText: '',
      headers: responseHeadersObj,
    })
  } catch (error) {
    // 触发 completed 拦截器（错误情况）
    for (const interceptor of completedInterceptors) {
      interceptor({
        id: requestId,
        url: req.url,
        method: req.method,
        timestamp: startTimestamp,
        referrer: req.referrer,
        fromCache: false,
        error: error instanceof Error ? error.message : String(error),
      })
    }
    throw error
  }
}

/**
 * 基于 sendHttpRequest 的 fetch API 实现
 * 提供类似标准 fetch 的接口，但底层使用 TTNet 库和 HTTP/2
 * @param input URL 或 Request 对象
 * @param init 可选的请求配置
 * @returns Promise<Response>
 */
export async function fetch(input: string | URL | Request, init?: RequestInit): Promise<Response> {
  let request: Request

  if (typeof input === 'string' || input instanceof URL) {
    // 从 URL 字符串创建 Request
    request = new Request(input.toString(), init)
  } else {
    // 直接使用 Request 对象
    request = input
  }

  return sendHttpRequest(request)
}

/**
 * 获取可以注入到 headers 里的 Cookie 头字符串
 * @param url 请求 URL
 * @returns Promise<string | null> Cookie 头字符串，如果没有 cookies 则返回 null
 */
export async function getCookiesHeader(url: string): Promise<string | null> {
  if (!app.isReady()) {
    return null
  }

  try {
    const cookies = await session.defaultSession.cookies.get({ url })
    const cookieHeader = cookies.map(cookie => `${cookie.name}=${cookie.value}`).join('; ')
    return cookieHeader
  } catch (error) {
    console.warn('Failed to get session cookies:', error)
    return null
  }
}

/**
 * 保存来自 headers 里的 Set-Cookie 字符串列表
 * @param url 请求 URL
 * @param setCookieHeaders Set-Cookie 头字符串数组
 * @returns Promise<void>
 */
export async function saveCookiesWithHeader(url: string, setCookieHeaders: string[]): Promise<void> {
  if (!app.isReady()) {
    return
  }

  try {
    const parsedCookies = setCookieParser.parse(setCookieHeaders, { map: false })

    for (const cookie of parsedCookies) {
      const attributes: CookiesSetDetails = {
        url,
        name: cookie.name,
        value: cookie.value,
      }

      if (cookie.domain) {
        attributes.domain = cookie.domain
      }
      if (cookie.path) {
        attributes.path = cookie.path
      }
      if (cookie.httpOnly) {
        attributes.httpOnly = true
      }
      if (cookie.secure) {
        attributes.secure = true
      }
      if (cookie.sameSite) {
        attributes.sameSite = convertSameSiteValue(cookie.sameSite)
      }
      if (cookie.expires) {
        attributes.expirationDate = Math.floor(cookie.expires.getTime() / 1000)
      } else if (cookie.maxAge) {
        attributes.expirationDate = Math.floor(Date.now() / 1000) + cookie.maxAge
      }

      try {
        await session.defaultSession.cookies.set(attributes)
      } catch (cookieError) {
        console.warn('Failed to set cookie:', attributes, cookieError)
      }
    }
  } catch (parseError) {
    console.warn('Failed to parse set-cookie headers:', setCookieHeaders, parseError)
  }
}
