import { session } from 'electron'
import { fetch } from '../../request'

type SuccessCallback<T> = (res: T) => void
type FailureCallback = (err: Error) => void

interface GetOptions<T> {
  url: string
  success?: SuccessCallback<T>
  fail?: FailureCallback
  withCredentials?: boolean
  getResponseText?: (responseText: XMLHttpRequest['responseText']) => void
}
interface PostOptions<T> {
  url: string
  data?: string
  success?: SuccessCallback<T>
  fail?: FailureCallback
}

interface TransportOptions<T> {
  url: string
  data?: string
  success?: SuccessCallback<T>
  fail?: FailureCallback
  getResponseText?: (responseText: XMLHttpRequest['responseText']) => void
  withCredentials?: boolean
}

const request = async <T>(
  method: 'GET' | 'POST',
  options: TransportOptions<T>,
) => {
  const { url, data, success, fail, getResponseText, withCredentials } = options

  try {
    let userAgent = ''
    try {
      session.defaultSession.getUserAgent()
    } catch {}
    const response = await fetch(url, {
      method,
      body: data,
      credentials: withCredentials ? 'include' : 'omit',
      headers: {
        'User-Agent': userAgent,
        'Content-Type': 'application/json',
      },
    })
    if (response.status >= 400) {
      throw new Error(await response.text())
    }
    const text = await response.text()
    if (text) {
      success?.(JSON.parse(text))
    } else {
      success?.({} as T)
    }
  } catch (e) {
    console.error(e)
    fail?.(e as Error)
  }
}

export const electronFetchTransport = {
  get(options: GetOptions<any>) {
    request('GET', options)
  },
  post(options: PostOptions<any>) {
    request('POST', options)
  },
}
